from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    grouped = defaultdict(list)
    for result in search_results:
        group_val = result.metadata.get(group_by_field, 'unknown')
        grouped[group_val].append(result)

    aggregated = {}
    if aggregation_funcs is None:
        aggregation_funcs = {}

    # Default aggregation functions
    default_aggs = {
        'count': lambda g: len(g),
        'avg_score': lambda g: sum(r.score for r in g) / len(g) if g else 0.0,
        'max_score': lambda g: max((r.score for r in g), default=0.0),
        'min_score': lambda g: min((r.score for r in g), default=0.0),
    }

    # Combine default and custom aggregation functions
    all_aggs = {**default_aggs, **aggregation_funcs}

    # Create reverse mapping for custom aggregation functions
    reverse_aggs = {v: k for k, v in aggregation_funcs.items()}

    for group_val, group_results in grouped.items():
        stats = {}
        for agg_name, agg_func in all_aggs.items():
            try:
                if agg_name in default_aggs:
                    # Use group_results as input
                    stats[agg_name] = agg_func(group_results)
                else:
                    # Use reverse mapping to get field name
                    field_name = reverse_aggs.get(agg_func)
                    if field_name is None:
                        continue
                    # Get field values from group_results
                    field_vals = [r.metadata.get(field_name, 0) for r in group_results]
                    stats[agg_name] = agg_func(field_vals)
            except Exception:
                # Skip if any error during aggregation
                continue
        aggregated[group_val] = stats

    return aggregated

